from dataclasses import dataclass, field
from datetime import date, datetime
from typing import List, Optional, Dict
from enum import Enum

class RitualType(Enum):
    SHOW_AND_TELL = "show_and_tell"
    CASE_STUDY = "case_study_review"
    POST_MORTEM = "failure_post_mortem"
    EXPERT_CLINIC = "expert_clinic"
    KNOWLEDGE_SPRINT = "knowledge_sprint"

@dataclass
class RitualSession:
    session_id: str
    ritual_type: RitualType
    title: str
    scheduled_date: date
    facilitator: str
    presenter: Optional[str]
    expected_attendees: int
    actual_attendees: Optional[int] = None
    satisfaction_score: Optional[float] = None  # 1-5
    output_published: bool = False
    output_url: str = ""
    learnings: List[str] = field(default_factory=list)

    def completion_rate(self) -> Optional[float]:
        if self.actual_attendees is None:
            return None
        return self.actual_attendees / self.expected_attendees * 100

    def is_high_value(self) -> bool:
        if self.satisfaction_score is None:
            return False
        return self.satisfaction_score >= 4.0 and (self.completion_rate() or 0) >= 70

    def status(self) -> str:
        if self.actual_attendees is None:
            return "scheduled"
        if not self.output_published:
            return "completed - output pending"
        return "completed"

@dataclass
class RitualCalendar:
    cop_name: str
    sessions: List[RitualSession] = field(default_factory=list)

    def add_session(self, session: RitualSession) -> None:
        self.sessions.append(session)

    def upcoming(self, days: int = 30) -> List[RitualSession]:
        today = date.today()
        return [
            s for s in self.sessions
            if today <= s.scheduled_date <= date.fromordinal(today.toordinal() + days)
        ]

    def sessions_without_output(self) -> List[RitualSession]:
        return [s for s in self.sessions if s.actual_attendees is not None and not s.output_published]

    def avg_satisfaction(self) -> Optional[float]:
        scored = [s.satisfaction_score for s in self.sessions if s.satisfaction_score is not None]
        return sum(scored) / len(scored) if scored else None

    def sessions_by_type(self) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for s in self.sessions:
            counts[s.ritual_type.value] = counts.get(s.ritual_type.value, 0) + 1
        return counts

    def report(self) -> str:
        lines = [
            f"Ritual Calendar: {self.cop_name}",
            f"Total sessions: {len(self.sessions)}",
            f"By type: {self.sessions_by_type()}",
            f"Avg satisfaction: {self.avg_satisfaction():.2f}/5.0"
            if self.avg_satisfaction() else "Avg satisfaction: No data yet",
            f"Sessions with unpublished output: {len(self.sessions_without_output())}",
        ]
        if self.sessions_without_output():
            lines.append("  Needs output publishing:")
            for s in self.sessions_without_output():
                lines.append(f"    - {s.title} ({s.scheduled_date})")
        return "\n".join(lines)

cal = RitualCalendar("GenAI Practitioners CoP")
cal.add_session(RitualSession(
    "S001", RitualType.SHOW_AND_TELL,
    "Prompt chaining for complex document analysis",
    date(2025, 9, 5), facilitator="Alex T.", presenter="Maria L.",
    expected_attendees=45, actual_attendees=38,
    satisfaction_score=4.3, output_published=True,
    output_url="/cop-hub/show-tell/S001",
    learnings=["Chained prompts reduce hallucination in 3-step extraction tasks",
                "Output validation step essential for legal content"]
))
cal.add_session(RitualSession(
    "S002", RitualType.POST_MORTEM,
    "AI summarisation incident - client report error (Aug 2025)",
    date(2025, 9, 19), facilitator="Alex T.", presenter=None,
    expected_attendees=30, actual_attendees=27,
    satisfaction_score=4.6, output_published=False
))
cal.add_session(RitualSession(
    "S003", RitualType.SHOW_AND_TELL,
    "Using AI for competitor analysis - three weeks in",
    date(2025, 10, 3), facilitator="Sarah B.", presenter="Tom H.",
    expected_attendees=40
))

print(cal.report())
